// The OBSBOT Tiny 2 vendor command table: 444 commands across all subsystems,
// 437 resolvable to a V3 wire opcode. Protocol data only — no OS coupling — so
// every platform transport (Windows/Linux/macOS) shares it.
//
// Potentially DESTRUCTIVE commands (firmware flashing, factory reset, SD format,
// power control, raw syscalls) are cordoned into a clearly-marked block at the
// end of the OPCODES table and re-exported as DESTRUCTIVE / DESTRUCTIVE_NAMES /
// isDestructive(). Anything dispatching opcodes by name should gate on those.

/** One vendor command and its wire addressing. */
export interface Opcode {
  /** Command enum member name, e.g. "AI_SET_GIM_SPEED". */
  name: string;
  /** Subsystem group: "Camera" | "Ai" | "Gimbal" | "SysMg" | "TXBle" | ... */
  subsystem: string;
  /** Logical command set (CmdSet enum value). */
  set: number;
  /** Logical command id within the subsystem (Cmd<Sub> enum value). */
  cmdId: number;
  /** 16-bit wire cmd (frame bytes 10-11, little-endian), or null if V0-only. */
  wireCmd: number | null;
  /** Receiver byte (frame byte 9), or null if V0-only. */
  receiver: number | null;
}

