/** Lookup by enum-member name (e.g. OP_BY_NAME.get("AI_SET_GIM_SPEED")). */
export const OP_BY_NAME: ReadonlyMap<string, Opcode> = new Map(
  OPCODES.map((o) => [o.name, o]),
);

/** Commands sendable over the V3 wire protocol (have a concrete wireCmd). */
export const SENDABLE: readonly Opcode[] = OPCODES.filter((o) => o.wireCmd !== null);

